#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 3 (Layer 2): array sistolico 8x8 output-stationary.
# Doble estimulo: feature maps reales + adversario (saturacion, signo, 64/64 PEs).
# Requiere: ghdl 4.1.0 --std=08, python3. Requiere Pasos 1 y 2 ya instalados.
# Linea esperada al final:
# NPU PASO3 OK L2 ARRAY PASS MUTACIONES 4/4 FAIL
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/model/npu_weights.hex" ] || [ ! -f "$DIR/rtl/npu_requant.vhd" ]; then
  echo "FALLO: faltan Pasos 1 y 2 en $DIR"; exit 1
fi
mkdir -p "$DIR/rtl" "$DIR/tb" "$DIR/vec" "$DIR/model"
base64 -d << "EOF" > "$DIR/rtl/npu_pe.vhd"

EOF
base64 -d << "EOF" > "$DIR/rtl/npu_array.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_npu_array.vhd"

EOF
base64 -d << "EOF" > "$DIR/gen_l2_vectors.py"

EOF
base64 -d << "EOF" > "$DIR/gen_l2_adversario.py"

EOF
base64 -d << "EOF" > "$DIR/model_systolic.py"

EOF
base64 -d << "EOF" > "$DIR/run_l2.sh"

EOF
chmod +x "$DIR/run_l2.sh"
cd "$DIR"
python3 model_systolic.py oracle/oracle_npu.py model/npu_weights.hex model/npu_golden.txt
python3 gen_l2_vectors.py oracle/oracle_npu.py model/npu_weights.hex model/npu_golden.txt vec 8
python3 gen_l2_adversario.py vec
bash run_l2.sh
)
